nection-size: 5\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      #Oracle需要打开注释\n      #validation-query: SELECT 1 FROM DUAL\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      # filter:\n      #   stat:\n      #     log-slow-sql: true\n      #     slow-sql-millis: 1000\n      #     merge-sql: false\n      #   wall:\n      #     config:\n      #       multi-statement-allow: true\n\nmybatis-plus:\n  mapper-locations: classpath*:/mapper/**/*.xml,classpath:/META-INF/modeler-mybatis-mappings/*.xml\n  #实体扫描，多个package用逗号或者分号分隔\n  typeAliasesPackage: io.renren.entity\n  global-config:\n    #数据库相关配置\n    db-config:\n      #主键类型\n      id-type: ASSIGN_ID\n    banner: false\n  #原生配置\n  configuration:\n    map-underscore-to-camel-case: true\n    cache-enabled: false\n    call-setters-on-nulls: true\n    jdbc-type-for-null: \"null\"\n  configuration-properties:\n    prefix:\n    blobType: BLOB\n    boolValue: TRUE\n', '4e25aaea8aed78a81dee24374b2e9230', '2025-12-09 19:20:04', '2025-12-09 19:20:04', 'nacos', '127.0.0.1', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
