t-per-connection-size: 5\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      #Oracle需要打开注释\n      #validation-query: SELECT 1 FROM DUAL\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      # filter:\n      #   stat:\n      #     log-slow-sql: true\n      #     slow-sql-millis: 1000\n      #     merge-sql: false\n      #   wall:\n      #     config:\n      #       multi-statement-allow: true\n\nmybatis-plus:\n  mapper-locations: classpath*:/mapper/**/*.xml,classpath:/META-INF/modeler-mybatis-mappings/*.xml\n  #实体扫描，多个package用逗号或者分号分隔\n  typeAliasesPackage: io.renren.entity\n  global-config:\n    #数据库相关配置\n    db-config:\n      #主键类型\n      id-type: ASSIGN_ID\n    banner: false\n  #原生配置\n  configuration:\n    map-underscore-to-camel-case: true\n    cache-enabled: false\n    call-setters-on-nulls: true\n    jdbc-type-for-null: \"null\"\n  configuration-properties:\n    prefix:\n    blobType: BLOB\n    boolValue: TRUE\n', '5642ba362f062e027d55281a0a749f76', '2026-01-06 12:30:32', '2026-01-06 12:30:32', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (3, 10, 'rocketmq.yaml', 'RENREN_CLOUD_GROUP', '', 'rocketmq:\n  name-server: 192.168.3.19:9876\n  producer:\n    group: ren-group\n    send-message-timeout: 300000 # 消息发送超时时长，默认3s\n\nrenren:\n  rocketmq:\n    orderTopic: orderTopic\n    payTopic: payTopic\n    orderConsumer: orderConsumer\n    payConsumer: payConsumer', 'c809636d2b3d7ea50f07e3e91d74e88f', '2026-01-06 12:31:23', '2026-01-06 12:31:24', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (5, 11, 'seata.properties', 'RENREN_CLOUD_GROUP', '', '#For details about configuration items, see https://seata.io/zh-cn/docs/user/configurations.html\ntransport.type=TCP\ntransport.server=NIO\ntransport.heartbeat=true\ntransport.enableTmClientBatchSendRequest=false\ntransport.enableRmClientBatchSendRequest=true\ntransport.enableTcServerBatchSendResponse=false\ntransport.rpcRmRequestTimeout=30000\ntransport.rpcTmRequestTimeout=30000\ntransport.rpcTcRequestTimeout=30000\ntransport.threadFactory.bossThreadPrefix=NettyBoss\ntransport.threadFactory.workerThreadPrefix=NettyServerNIOWorker\ntransport.threadFactory.serverExecutorThreadPrefix=NettyServerBizHandler\ntransport.threadFactory.shareBossWorker=false\ntransport.threadFactory.clientSelectorThreadPrefix=NettyClientSelector\ntransport.threadFactory.clientSelectorThreadSize=1\ntransport.threadFactory.clientWorkerThreadPrefix=NettyClientWorkerThread\ntransport.threadFactory.bossThreadSize=1\ntransport.threadFactory.workerThreadSize=default\ntransport.shutdown.wait=3\ntransport.serialization=seata\ntransport.compressor=none\n\n#Transaction routing rules configuration, only for the client\nservice.vgroupMapping.default_tx_group=default\n#If you use a registry, you can ignore it\nservice.default.grouplist=127.0.0.1:8091\nservice.enableDegrade=false\nservice.disableGlobalTransaction=false\n\n#Transaction rule configuration, only for the client\nclient.rm.asyncCommitBufferLimit=10000\nclient.rm.lock.retryInterval=10\nclient.rm.lock.retryTimes=30\nclient.rm.lock.retryPolicyBranchRollbackOnConflict=true\nclient.rm.reportRetryCount=5\nclient.rm.tableMetaCheckEnable=true\nclient.rm.tableMetaCheckerInterval=60000\nclient.rm.sqlParserType=druid\nclient.rm.reportSuccessEnable=false\nclient.rm.sagaBranchRegisterEnable=false\nclient.rm.sagaJsonParser=fastjson\nclient.rm.tccActionInterceptorOrder=-2147482648\nclient.tm.commitRetryCount=5\nclient.tm.rollbackRetryCount=5\nclient.tm.defaultGlobalTransactionTimeout=60000\nclient.tm.degradeCheck=false\nclient.tm.degradeCheckAllowTimes=10\nclient.tm.degradeCheckPeriod=2000\nclient.tm.interceptorOrder=-2147482648\nclient.undo.dataValidation=true\nclient.undo.logSerialization=jackson\nclient.undo.onlyCareUpdateColumns=true\nserver.undo.logSaveDays=7\nserver.undo.logDeletePeriod=86400000\nclient.undo.logTable=undo_log\nclient.undo.compress.enable=true\nclient.undo.compress.type=zip\nclient.undo.compress.threshold=64k\n#For TCC transaction mode\ntcc.fence.logTableName=tcc_fence_log\ntcc.fence.cleanPeriod=1h\n\n#Log rule configuration, for client and server\nlog.exceptionRate=100\n\n#Transaction storage configuration, only for the server. The file, db, and redis configuration values are optional.\nstore.mode=db\nstore.lock.mode=db\nstore.session.mode=db\n#Used for password encryption\n#store.publicKey=\n\n\n\n#These configurations are required if the `store mode` is `db`. If `store.mode,store.lock.mode,store.session.mode` are not equal to `db`, you can remove the configuration block.\nstore.db.datasource=druid\nstore.db.dbType=mysql\nstore.db.driverClassName=com.mysql.cj.jdbc.Driver\nstore.db.url=jdbc:mysql://127.0.0.1:3306/seata?useUnicode=true&rewriteBatchedStatements=true\nstore.db.user=root\nstore.db.password=123456\nstore.db.minConn=5\nstore.db.maxConn=30\nstore.db.globalTable=global_table\nstore.db.branchTable=branch_table\nstore.db.distributedLockTable=distributed_lock\nstore.db.queryLimit=100\nstore.db.lockTable=lock_table\nstore.db.maxWait=5000\n\n\n#Transaction rule configuration, only for the server\nserver.recovery.committingRetryPeriod=1000\nserver.recovery.asynCommittingRetryPeriod=1000\nserver.recovery.rollbackingRetryPeriod=1000\nserver.recovery.timeoutRetryPeriod=1000\nserver.maxCommitRetryTimeout=-1\nserver.maxRollbackRetryTimeout=-1\nserver.rollbackRetryTimeoutUnlockEnable=false\nserver.distributedLockExpireTime=10000\nserver.xaerNotaRetryTimeout=60000\nserver.session.branchAsyncQueueSize=5000\nserver.session.enableBranchAsyncRemove=false\nserver.enableParallelRequestHandle=false', '1c15f5d1bf59658e068635f67b0d3bb4', '2026-01-06 12:32:15', '2026-01-06 12:32:16', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"properties\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (3, 12, 'rocketmq.yaml', 'RENREN_CLOUD_GROUP', '', 'rocketmq:\n  name-server: 192.168.3.19:9876\n  producer:\n    group: ren-group\n    send-message-timeout: 300000 # 消息发送超时时长，默认3s\n\njslh:\n  rocketmq:\n    orderTopic: orderTopic\n    payTopic: payTopic\n    orderConsumer: orderConsumer\n    payConsumer: payConsumer', '8c0e519030bf034e9d550e099d7e4ddb', '2026-01-06 12:35:29', '2026-01-06 12:35:30', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (4, 13, 'gateway.json', 'RENREN_CLOUD_GROUP', '', '[\n  {\n    \"remark\": \"Admin服务\",\n    \"id\": \"renren-admin-server\",\n    \"uri\": \"lb://renren-admin-server\",\n    \"order\": \"2\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/sys/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"监控服务\",\n    \"id\": \"renren-monitor-server\",\n    \"uri\": \"lb://renren-monitor-server\",\n    \"order\": \"3\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/monitor/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"OSS服务\",\n    \"id\": \"renren-oss-server\",\n    \"uri\": \"lb://renren-oss-server\",\n    \"order\": \"4\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/oss/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"消息服务\",\n    \"id\": \"renren-message-server\",\n    \"uri\": \"lb://renren-message-server\",\n    \"order\": \"5\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/message/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"工作流服务\",\n    \"id\": \"renren-flow-server\",\n    \"uri\": \"lb://renren-flow-server\",\n    \"order\": \"6\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/flow/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"定时任务服务\",\n    \"id\": \"renren-job-server\",\n    \"uri\": \"lb://renren-job-server\",\n    \"order\": \"7\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/job/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"APP流服务\",\n    \"id\": \"renren-api-server\",\n    \"uri\": \"lb://renren-api-server\",\n    \"order\": \"8\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/api/**\"\n        }\n      }\n    ]\n  },\n  {\n    \"remark\": \"代码生成服务\",\n    \"id\": \"renren-devtools-server\",\n    \"uri\": \"lb://renren-devtools-server\",\n    \"order\": \"9\",\n    \"predicates\": [\n      {\n        \"name\": \"Path\",\n        \"args\": {\n          \"pattern\": \"/devtools/**\"\n        }\n      }\n    ]\n  }\n]', 'cc2a24c7f6eecc80c1b7ea1700183d53', '2026-01-06 12:37:05', '2026-01-06 12:37:06', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"json\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (2, 14, 'datasource.yaml', 'RENREN_CLOUD_GROUP', '', 'spring:\r\n  data:\r\n    redis:\r\n      host: 127.0.0.1\r\n      port: 6379\r\n      database: 0\r\n      password: qwer@123\r\n      timeout: 30s\r\n  datasource:\r\n    druid:\r\n      #MySQL\r\n      driver-class-name: com.mysql.cj.jdbc.Driver\r\n      url: jdbc:mysql://localhost:3306/jslh_cloud_tenant?useUnicode=true&characterEncoding=UTF-8&useSSL=false&allowPublicKeyRetrieval=true&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true\r\n      username: root\r\n      password: qwer1234\r\n      #DM8\r\n      # driver-class-name: dm.jdbc.driver.DmDriver\r\n      # url: jdbc:dm://localhost:5236/renren_cloud?useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&compatibleMode=oracle\r\n      # username: renren_cloud\r\n      # password: dm12345678\r\n      #Oracle\r\n      # driver-class-name: oracle.jdbc.OracleDriver\r\n      # url: jdbc:oracle:thin:@localhost:1521:xe\r\n      # username: renren_security\r\n      # password: 123456\r\n      #SQLServer\r\n      # driver-class-name: com.microsoft.sqlserver.jdbc.SQLServerDriver\r\n      # url: jdbc:sqlserver://localhost:1433;DatabaseName=renren_cloud\r\n      # username: sa\r\n      # password: 123456\r\n      #postgresql\r\n      # driver-class-name: org.postgresql.Driver\r\n      # url: jdbc:postgresql://localhost:5432/renren_cloud\r\n      # username: postgres\r\n      # password: 123456\r\n      #openGauss\r\n      # driver-class-name: org.postgresql.Driver\r\n      # url: jdbc:postgresql://localhost:5432/renren_cloud\r\n      # username: gaussdb\r\n      # password: openGauss@123\r\n      #KingbaseES\r\n      # driver-class-name: org.postgresql.Driver\r\n      # url: jdbc:postgresql://localhost:54321/renren_cloud?currentSchema=public,SYS_CATALOG\r\n      # username: system\r\n      # password: Kingbase123\r\n      initial-size: 2\r\n      max-active: 5\r\n      min-idle: 2\r\n      max-wait: 6000\r\n      pool-prepared-statements: true\r\n      max-pool-prepared-statement-per-connection-size: 5\r\n      time-between-eviction-runs-millis: 60000\r\n      min-evictable-idle-time-millis: 300000\r\n      #Oracle需要打开注释\r\n      #validation-query: SELECT 1 FROM DUAL\r\n      test-while-idle: true\r\n      test-on-borrow: false\r\n      test-on-return: false\r\n      # filter:\r\n      #   stat:\r\n      #     log-slow-sql: true\r\n      #     slow-sql-millis: 1000\r\n      #     merge-sql: false\r\n      #   wall:\r\n      #     config:\r\n      #       multi-statement-allow: true\r\n\r\nmybatis-plus:\r\n  mapper-locations: classpath*:/mapper/**/*.xml,classpath:/META-INF/modeler-mybatis-mappings/*.xml\r\n  #实体扫描，多个package用逗号或者分号分隔\r\n  typeAliasesPackage: io.renren.entity\r\n  global-config:\r\n    #数据库相关配置\r\n    db-config:\r\n      #主键类型\r\n      id-type: ASSIGN_ID\r\n    banner: false\r\n  #原生配置\r\n  configuration:\r\n    map-underscore-to-camel-case: true\r\n    cache-enabled: false\r\n    call-setters-on-nulls: true\r\n    jdbc-type-for-null: \"null\"\r\n  configuration-properties:\r\n    prefix:\r\n    blobType: BLOB\r\n    boolValue: TRUE\r\n', '6392cec46a2b399db4fead899f4e2cad', '2026-01-06 12:47:10', '2026-01-06 12:47:11', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (1, 15, 'common.yaml', 'JSLH_CLOUD_GROUP', '', 'spring:\n  cloud:\n    sentinel:\n      enabled: true\n      transport:\n        # sentinel dashboard 地址\n        dashboard: localhost:8180\n\njslh:\n  xss:\n    enabled: true\n    exclude-urls:\n      - /model\n\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"\n  endpoint:\n    health:\n      show-details: ALWAYS\n\nfeign:\n  sentinel:\n    enabled: true\n  client:\n    config:\n      default:\n        loggerLevel: FULL\n  httpclient:\n    enabled: true\n\n\nribbon:\n  ReadTimeout: 300000\n  ConnectTimeout: 300000    ', '72ee4ed90d32d8bb1416327ea1326cba', '2026-01-06 12:51:39', '2026-01-06 12:51:40', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (2, 16, 'datasource.yaml', 'JSLH_CLOUD_GROUP', '', 'spring:\n  data:\n    redis:\n      host: 127.0.0.1\n      port: 6379\n      database: 0\n      password: qwer@123\n      timeout: 30s\n  datasource:\n    druid:\n      #MySQL\n      driver-class-name: com.mysql.cj.jdbc.Driver\n      url: jdbc:mysql://localhost:3306/jslh clould tenant?useUnicode=true&characterEncoding=UTF-8&useSSL=false&allowPublicKeyRetrieval=true&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true\n      username: root\n      password: qwer1234\n      #DM8\n      # driver-class-name: dm.jdbc.driver.DmDriver\n      # url: jdbc:dm://localhost:5236/renren_cloud?useUnicode=true&characterEncoding=UTF-8&serverTimezone=Asia/Shanghai&nullCatalogMeansCurrent=true&compatibleMode=oracle\n      # username: renren_cloud\n      # password: dm12345678\n      #Oracle\n      # driver-class-name: oracle.jdbc.OracleDriver\n      # url: jdbc:oracle:thin:@localhost:1521:xe\n      # username: renren_security\n      # password: 123456\n      #SQLServer\n      # driver-class-name: com.microsoft.sqlserver.jdbc.SQLServerDriver\n      # url: jdbc:sqlserver://localhost:1433;DatabaseName=renren_cloud\n      # username: sa\n      # password: 123456\n      #postgresql\n      # driver-class-name: org.postgresql.Driver\n      # url: jdbc:postgresql://localhost:5432/renren_cloud\n      # username: postgres\n      # password: 123456\n      #openGauss\n      # driver-class-name: org.postgresql.Driver\n      # url: jdbc:postgresql://localhost:5432/renren_cloud\n      # username: gaussdb\n      # password: openGauss@123\n      #KingbaseES\n      # driver-class-name: org.postgresql.Driver\n      # url: jdbc:postgresql://localhost:54321/renren_cloud?currentSchema=public,SYS_CATALOG\n      # username: system\n      # password: Kingbase123\n      initial-size: 2\n      max-active: 5\n      min-idle: 2\n      max-wait: 6000\n      pool-prepared-statements: true\n      max-pool-prepared-statement-per-connection-size: 5\n      time-between-eviction-runs-millis: 60000\n      min-evictable-idle-time-millis: 300000\n      #Oracle需要打开注释\n      #validation-query: SELECT 1 FROM DUAL\n      test-while-idle: true\n      test-on-borrow: false\n      test-on-return: false\n      # filter:\n      #   stat:\n      #     log-slow-sql: true\n      #     slow-sql-millis: 1000\n      #     merge-sql: false\n      #   wall:\n      #     config:\n      #       multi-statement-allow: true\n\nmybatis-plus:\n  mapper-locations: classpath*:/mapper/**/*.xml,classpath:/META-INF/modeler-mybatis-mappings/*.xml\n  #实体扫描，多个package用逗号或者分号分隔\n  typeAliasesPackage: io.renren.entity\n  global-config:\n    #数据库相关配置\n    db-config:\n      #主键类型\n      id-type: ASSIGN_ID\n    banner: false\n  #原生配置\n  configuration:\n    map-underscore-to-camel-case: true\n    cache-enabled: false\n    call-setters-on-nulls: true\n    jdbc-type-for-null: \"null\"\n  configuration-properties:\n    prefix:\n    blobType: BLOB\n    boolValue: TRUE\n', '68c0c5b99d671d0c23bf60cd9abf8521', '2026-01-06 12:52:06', '2026-01-06 12:52:06', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');
INSERT INTO `his_config_info` VALUES (1, 17, 'common.yaml', 'JSLH_CLOUD_GROUP', '', 'spring:\n  cloud:\n    sentinel:\n      enabled: true\n      transport:\n        # sentinel dashboard 地址\n        dashboard: localhost:8180\n\njslh:\n  xss:\n    enabled: true\n    exclude-urls:\n      - /model\n\nmanagement:\n  endpoints:\n    web:\n      exposure:\n        include: \"*\"\n  endpoint:\n    health:\n      show-details: ALWAYS\n\nfeign:\n  sentinel:\n    enabled: true\n  client:\n    config:\n      default:\n        loggerLevel: FULL\n  httpclient:\n    enabled: true\n\n\nribbon:\n  ReadTimeout: 300000\n  ConnectTimeout: 300000    ', '72ee4ed90d32d8bb1416327ea1326cba', '2026-01-06 12:52:14', '2026-01-06 12:52:15', 'nacos', '192.168.1.89', 'U', 'public', '', 'formal', '', '{\"type\":\"yaml\",\"src_user\":\"nacos\"}');

-- ----------------------------
-- Table structure for permissions
-- ----------------------------
DROP TABLE IF EXISTS `permissions`;
CREATE TABLE `permissions`  (
  `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'role',
  `resource` varchar(128) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'resource',
  `action` varchar(8) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'action',
  UNIQUE INDEX `uk_role_permission`(`role`, `resource`, `action`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for roles
-- ----------------------------
DROP TABLE IF EXISTS `roles`;
CREATE TABLE `roles`  (
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'username',
  `role` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'role',
  UNIQUE INDEX `idx_user_role`(`username`, `role`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of roles
-- ----------------------------
INSERT INTO `roles` VALUES ('nacos', 'ROLE_ADMIN');

-- ----------------------------
-- Table structure for tenant_capacity
-- ----------------------------
DROP TABLE IF EXISTS `tenant_capacity`;
CREATE TABLE `tenant_capacity`  (
  `id` bigint(0) UNSIGNED NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL DEFAULT '' COMMENT 'Tenant ID',
  `quota` int(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '配额，0表示使用默认值',
  `usage` int(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '使用量',
  `max_size` int(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个配置大小上限，单位为字节，0表示使用默认值',
  `max_aggr_count` int(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '聚合子配置最大个数',
  `max_aggr_size` int(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '单个聚合数据的子配置大小上限，单位为字节，0表示使用默认值',
  `max_history_count` int(0) UNSIGNED NOT NULL DEFAULT 0 COMMENT '最大变更历史数量',
  `gmt_create` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '创建时间',
  `gmt_modified` datetime(0) NOT NULL DEFAULT CURRENT_TIMESTAMP(0) COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_tenant_id`(`tenant_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = '租户容量信息表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for tenant_info
-- ----------------------------
DROP TABLE IF EXISTS `tenant_info`;
CREATE TABLE `tenant_info`  (
  `id` bigint(0) NOT NULL AUTO_INCREMENT COMMENT 'id',
  `kp` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NOT NULL COMMENT 'kp',
  `tenant_id` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT 'tenant_id',
  `tenant_name` varchar(128) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT '' COMMENT 'tenant_name',
  `tenant_desc` varchar(256) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'tenant_desc',
  `create_source` varchar(32) CHARACTER SET utf8 COLLATE utf8_bin NULL DEFAULT NULL COMMENT 'create_source',
  `gmt_create` bigint(0) NOT NULL COMMENT '创建时间',
  `gmt_modified` bigint(0) NOT NULL COMMENT '修改时间',
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `uk_tenant_info_kptenantid`(`kp`, `tenant_id`) USING BTREE,
  INDEX `idx_tenant_id`(`tenant_id`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8 COLLATE = utf8_bin COMMENT = 'tenant_info' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Table structure for users
-- ----------------------------
DROP TABLE IF EXISTS `users`;
CREATE TABLE `users`  (
  `username` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'username',
  `password` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT 'password',
  `enabled` tinyint(1) NOT NULL COMMENT 'enabled',
  PRIMARY KEY (`username`) USING BTREE
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci ROW_FORMAT = Dynamic;

